/// <summary>
///  blank out the Batch ID on rate card form (after click on add button)
/// </summary>
[ExtensionOf(formDataSourceStr(ETGPurchRateCard, TmpInventDim))]
internal final class ETGPurchRateCard_Extension
{
    public static boolean bEmptyInitialBatchID = false;
}

Method.Source:
public void initValue()
{
    next initValue();

    bEmptyInitialBatchID = true;
}

[FormDataSourceEventHandler(formDataSourceStr(ETGPurchRateCard, TmpInventDim), FormDataSourceEventType::Activated)]
public static void TmpInventDim_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    InventDim inventDim = sender.cursor() as InventDim;

    if (bEmptyInitialBatchID && inventDim && inventDim.InventBatchId)
    {
        inventDim.InventBatchId = '';
        inventDim.modifiedField(fieldNum(InventDim, InventBatchId));
        bEmptyInitialBatchID = false;
    }
}
